const path: string[] = [];
function dfs(node: string): boolean {
  if (color[node] === 'G') return true;
  if (color[node] === 'B') return false;
  color[node] = 'G'; path.push(node);
  for (const dep of graph[node] ?? []) { if (dfs(dep)) return true; }
